"use strict";parserFactory.register("travistranslations.com",()=>new TravistranslationsParser);class TravistranslationsParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll("section.mb-4 ul.grid a")].map(e=>({sourceUrl:e.href,title:e.querySelector("span").textContent.trim()}))}findContent(e){return e.querySelector("div.reader-content")}extractTitleImpl(e){return e.querySelector("h1[title]")}findChapterTitle(e){let t=e.querySelector("div.header h2"),r=t.parentElement.querySelector("span")?.textContent??"";return t.textContent+" "+r}findCoverImageUrl(e){return util.getFirstImgSrc(e,"#primary .container")?.replace("q=55","q=100")??null}preprocessRawDom(e){util.resolveLazyLoadedImages(e,"img"),this.addAuthorNotes(e)}addAuthorNotes(e){let t=this.findContent(e);for(let e of[...t.parentElement.querySelectorAll("div.py-1")])t.append(e)}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div[property='description']")]}}